import type { Achievement } from '../types'

function a(
  id: string,
  name: string,
  category: string,
  type: 'positive' | 'negative',
  rarity: Achievement['rarity'],
  xp: number,
  background: string,
  image: string,
  isSecret: boolean,
  supportsMixer: boolean,
  descM: string,
  descF: string,
): Achievement {
  return {
    id,
    name,
    category,
    type,
    rarity,
    xp,
    background,
    image,
    isSecret,
    supportsMixer,
    isUnlocked: false,
    isFreshUnlock: false,
    isMixerConsumed: false,
    descriptionMale: descM,
    descriptionFemale: descF,
  }
}

// Helper: convert spec title to art filename (lowercase + .webp)
function artFile(title: string): string {
  const map: Record<string, string> = {
    'Медвежья берлога': 'мевежья берлога.webp',
  }
  if (map[title]) return map[title]
  return title.toLowerCase() + '.webp'
}

// Helper: for missing art, use empty string — UI will show placeholder
function artFileOrMissing(title: string, hasImage: boolean): string {
  if (!hasImage) return ''
  return artFile(title)
}

